import{_ as n,C as o,o as l,c as s,E as a,w as t,a as r,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Lithuania Legal Rights","description":"Legal rights for transgender people in Lithuania","frontmatter":{"layout":"doc","title":"Lithuania Legal Rights","description":"Legal rights for transgender people in Lithuania"},"headers":[],"relativePath":"europe/lithuania/legal-rights.md","filePath":"europe/lithuania/legal-rights.md","lastUpdated":null}'),h={name:"europe/lithuania/legal-rights.md"};function c(g,e,u,m,p,f){const i=o("Badge");return l(),s("div",null,[a(i,{variant:"red"},{default:t(()=>[...e[0]||(e[0]=[r("Surgery + Court Barriers",-1)])]),_:1}),a(i,{variant:"yellow"},{default:t(()=>[...e[1]||(e[1]=[r("Anti-Discrimination",-1)])]),_:1}),a(i,{variant:"red"},{default:t(()=>[...e[2]||(e[2]=[r("Growing Judicial Barriers",-1)])]),_:1}),e[3]||(e[3]=d('<h1 id="legal-rights-in-lithuania" tabindex="-1">Legal Rights in Lithuania <a class="header-anchor" href="#legal-rights-in-lithuania" aria-label="Permalink to &quot;Legal Rights in Lithuania&quot;">​</a></h1><h2 id="gender-recognition" tabindex="-1">Gender Recognition <a class="header-anchor" href="#gender-recognition" aria-label="Permalink to &quot;Gender Recognition&quot;">​</a></h2><p>Lithuania has a restrictive gender recognition system made more difficult by a 2020 Constitutional Court ruling:</p><ul><li><strong>Requirements</strong>: Diagnosis of gender dysphoria + HRT + sex reassignment surgery</li><li><strong>Constitutional Court Ruling (2020)</strong>: The court ruled that a person who has changed gender must be considered as having the &quot;acquired sex,&quot; but this also reinforced the medicalized model</li><li><strong>Age</strong>: 18+ only</li><li><strong>Process</strong>: Application through the Civil Registry (Civilinės metrikacijos skyrius) with medical certification</li><li><strong>Surgery</strong>: Effectively required for legal recognition</li></ul><h3 id="the-process" tabindex="-1">The Process <a class="header-anchor" href="#the-process" aria-label="Permalink to &quot;The Process&quot;">​</a></h3><ol><li>Diagnosis from a psychiatrist or gender clinic (Santaros Clinics, Vilnius)</li><li>Minimum 1-2 years of documented HRT and real-life experience</li><li>Sex reassignment surgery</li><li>Court or administrative application for gender marker change</li><li>Updated identity documents</li></ol><p><strong>Note</strong>: The Constitutional Court ruling has been interpreted conservatively by lower courts, making legal gender change harder to obtain. Several cases have been rejected or delayed.</p><h2 id="name-changes" tabindex="-1">Name Changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name Changes&quot;">​</a></h2><ul><li>Name change is processed through the <strong>Civil Registry</strong></li><li>Can be done separately from gender marker change in some cases</li><li>Requires a valid reason — gender transition is generally accepted</li><li>Processed within 1-3 months</li></ul><h2 id="anti-discrimination-laws" tabindex="-1">Anti-Discrimination Laws <a class="header-anchor" href="#anti-discrimination-laws" aria-label="Permalink to &quot;Anti-Discrimination Laws&quot;">​</a></h2><ul><li><strong>Employment</strong>: Prohibited under the Labour Code</li><li><strong>Goods and Services</strong>: Protected under the Equal Treatment Law</li><li><strong>Education</strong>: General non-discrimination provisions apply</li></ul><p>The <strong>Law on Equal Treatment</strong> prohibits discrimination based on sexual orientation but does not explicitly list gender identity. The protection is often interpreted as covering gender identity by extension.</p><h2 id="hate-crime-laws" tabindex="-1">Hate Crime Laws <a class="header-anchor" href="#hate-crime-laws" aria-label="Permalink to &quot;Hate Crime Laws&quot;">​</a></h2><ul><li>The <strong>Criminal Code</strong> includes hate crime provisions covering race, religion, nationality</li><li>Sexual orientation is included as a protected characteristic</li><li>Gender identity is <strong>not explicitly mentioned</strong></li><li>A 2019 amendment to add gender identity failed to pass</li><li>Some municipalities have local anti-discrimination measures</li></ul><h2 id="document-recognition" tabindex="-1">Document Recognition <a class="header-anchor" href="#document-recognition" aria-label="Permalink to &quot;Document Recognition&quot;">​</a></h2><ul><li>Updated passports and ID cards are recognized internationally</li><li>Previous documents are archived but not publicly accessible</li><li>Lithuanian passports are valid for travel within the Schengen Area</li><li>Some trans people report difficulties with document checks at borders</li></ul><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://sam.lrv.lt/" target="_blank" rel="noreferrer">Lithuanian Ministry of Health</a></li><li><a href="https://www.lgl.lt/" target="_blank" rel="noreferrer">LGL (National LGBT Rights Organization)</a></li><li><a href="https://transautonomija.lt/" target="_blank" rel="noreferrer">Trans Autonomija</a></li><li><a href="https://www.lygybe.lt/" target="_blank" rel="noreferrer">Office of the Equal Opportunities Ombudsperson</a></li></ul>',18))])}const v=n(h,[["render",c]]);export{y as __pageData,v as default};
